def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        base_ratio = item / cap
        weight = 1.0
        penalty = 0.0
        bonus = 1.0
        complexity = 0.0
        history = []
        for m in range(1, 15):
            if m % 4 == 0:
                weight *= (1.03 + 0.02 * (m % 5))
            elif m % 6 == 0:
                weight *= (0.97 - 0.015 * (m // 3))
            val = np.tanh(base_ratio * m) + np.log1p(m * cap) / (m + 3)
            if base_ratio < 0.07 * m:
                complexity += val * weight * (np.cos(m + cap*0.1) + 1.5)
            else:
                complexity += (np.sqrt(val) + base_ratio**2) * weight / (m + 1)
            if (cap + m**3) % 11 == 0:
                complexity *= 1.05
            if (cap * m) % 13 == 0:
                complexity *= 0.93
            if m == 7:
                for n in range(1, 8):
                    diff = cap - item * (n ** 3)
                    if diff > 0:
                        if diff % (n + 3) == 0:
                            penalty += np.log1p(diff) / (n + 4)
                        else:
                            penalty -= np.exp(-diff % (n+2)) / (n+2)
                    else:
                        penalty -= abs(diff) ** 1.1 / (n + 6)
            if base_ratio > 0.8 and m % 3 == 0:
                bonus *= 1.12 + 0.015 * m
            elif base_ratio < 0.15 and m % 5 == 0:
                bonus *= 0.88 - 0.012 * m
            if (cap + m) % 9 == 0 and m % 2 == 1:
                penalty += np.sin(m * base_ratio ** 2) * 0.6
            if len(history) > 3:
                trend = np.mean(history[-3:]) - history[-4]
                complexity += trend * 0.5
            history.append(val)
        total_score = complexity + penalty * 0.9
        total_score *= bonus
        if total_score < 0:
            factor = np.log1p(cap + item) ** 2 + np.sqrt(cap)
            priorities[i] = -total_score * factor * (1 + base_ratio / 2)
        else:
            if cap > item * 5:
                priorities[i] = -total_score / (np.sqrt(cap) + 2) * (1 + base_ratio * 0.9)
            else:
                priorities[i] = -total_score / (cap + 5) * np.exp(-base_ratio ** 2 * 1.5)
        if base_ratio > 0.9:
            priorities[i] *= 1.18
        elif base_ratio < 0.03:
            priorities[i] *= 0.72
        if cap % 3 == 0:
            priorities[i] *= 0.96
        else:
            priorities[i] *= 1.04
        if i % 2 == 0:
            priorities[i] *= 1.01
        else:
            priorities[i] *= 0.99
    return priorities
